def test_search_patient_single_char_name_boundary(
    clinician_auth_headers, fhir_client, audit_poller, assigned_patient_starting_with_a
):
    r = fhir_client.get("/Patient", params={"name": "A"}, headers=clinician_auth_headers)
    assert r.status_code == 200, f"Single-char name should be valid, got {r.status_code}"
    bundle = r.json()
    assert bundle["resourceType"] == "Bundle"
    care_ids = {p["id"] for p in assigned_patient_starting_with_a["care_list"]}
    for entry in bundle.get("entry", []):
        pid = entry["resource"]["id"]
        assert pid in care_ids, f"{pid} not in clinician care list"
    audit = audit_poller("/AuditEvent", entity_type="Patient", action="E")
    assert len(audit) >= 1
